ha-card {
  --card-mod-font-size: 3em;
  text-align: center;
  padding: 16px;
}
.icon-container {
  margin-top: -10px;
}
.main {
  font-size: 5em;
  font-weight: bold;
}
.secondary {
  font-size: 1.5em;
  color: var(--secondary-text-color);
}

cards.icon:
{% if is_state('sensor.fredericton_current_condition', 'Sunny') %}
  mdi:weather-sunny
{% elif is_state('sensor.fredericton_current_condition', 'Rainy') %}
  mdi:weather-rainy
{% elif is_state('sensor.fredericton_current_condition', 'Cloudy') %}
  mdi:weather-cloudy
{% elif is_state('sensor.fredericton_current_condition', 'Snowy') %}
  mdi:weather-snowy
{% elif is_state('sensor.fredericton_current_condition', 'Windy') %}
  mdi:weather-windy
{% else %}
  mdi:weather-partly-cloudy
{% endif %}

cards.color:
{% if is_state('sensor.fredericton_current_condition', 'Sunny') %}
  yellow
{% elif is_state('sensor.fredericton_current_condition', 'Rainy') %}
  blue
{% elif is_state('sensor.fredericton_current_condition', 'Cloudy') %}
  gray
{% elif is_state('sensor.fredericton_current_condition', 'Snowy') %}
  white
{% elif is_state('sensor.fredericton_current_condition', 'Windy') %}
  green
{% else %}
  lightgray
{% endif %}

cards.icon:
[[[
  const s = entity.state;
  if (s === 'In the Common Room') return 'mdi:fireplace';
  if (s === 'Diagon Alley') return 'mdi:shopping';
  if (s === 'Forbidden Forest') return 'mdi:pine-tree';
  if (s === 'Quidditch Practice') return 'mdi:creation';
  if (s === 'Dragon Feeding') return 'mdi:dragon';
  if (s === 'Seaside Sorcery') return 'mdi:waves';
  if (s === 'Beyond the Kingdom') return 'mdi:castle';
  if (s === 'Ministry Business') return 'mdi:briefcase';
  if (s === 'Mortal Peril') return 'mdi:skull-crossbones';
  return 'mdi:compass';
]]]

cards.label:
[[[
  const p = states['person.admin'];
  return p ? `Raw zone: ${p.state}` : 'Raw zone: unavailable';
]]]

